using Dapper;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
using Valora.Infrastructure.Database;

namespace Valora.Infrastructure.Repositories;
public sealed class PlanRepository(IDbConnectionFactory f):IPlanRepository{ public async Task<IReadOnlyList<PlanDto>> GetPublicPlansAsync(){using var c=f.Create(); var plans=(await c.QueryAsync<dynamic>("SELECT * FROM valorapesquisa.plans WHERE visible_on_public_pricing=true AND status='active' ORDER BY display_order")).ToList(); var result=new List<PlanDto>(); foreach(var p in plans) result.Add(await Hydrate((string)p.id,p)); return result;} public async Task<PlanDto?> GetByIdAsync(string id){using var c=f.Create(); var p=await c.QuerySingleOrDefaultAsync<dynamic>("SELECT * FROM valorapesquisa.plans WHERE id=@id",new{id}); return p is null?null:await Hydrate(id,p);} async Task<PlanDto> Hydrate(string id,dynamic p){using var c=f.Create(); var limits=(await c.QueryAsync<(string limit_key,int limit_value)>("SELECT limit_key,limit_value FROM valorapesquisa.plan_limits WHERE plan_id=@id",new{id})).ToDictionary(x=>x.limit_key,x=>x.limit_value); var caps=(await c.QueryAsync<(string capability_key,string capability_level)>("SELECT capability_key,capability_level FROM valorapesquisa.plan_capabilities WHERE plan_id=@id",new{id})).ToDictionary(x=>x.capability_key,x=>x.capability_level); return new(id,(string)p.name,(string?)p.badge,(string)p.price_label,(string?)p.price_complement,(int)p.display_order,limits,caps);} public async Task<string?> GetCurrentPlanIdAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<string?>("SELECT plan_id FROM valorapesquisa.subscriptions WHERE organization_id=@organizationId AND status='active' ORDER BY created_at DESC LIMIT 1",new{organizationId});} public async Task CreateSubscriptionAsync(Guid organizationId,string planId){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO valorapesquisa.subscriptions(organization_id,plan_id) VALUES (@organizationId,@planId)",new{organizationId,planId});}}
